UPDATE public.nl_training_chapters

SET content = content || E'\n\n---\n\n## Hair Salon Cold Call Script\n*Updated June 21, 2026 — Priority Script*\n\n### Receptionist\n- "Hey, is this [business] in [city]?"\n- "Ok so I was reading your reviews and someone left a 1-star that said \'they made me look too good and now my ex won\'t leave me alone\' — is that true or did I misread that?"\n- "Because that\'s 5 stars to me. I\'m not sure what that person\'s problem is."\n- "Anyways, do you know Charlotte by chance — Charlotte Honeywell?"\n- "Well she\'s one of your customers and she says great things about you guys. She\'s basically your number 1 salesman at this point. I\'ve heard amazing things about y\'all."\n- "I was referred here to talk to [owner], any chance they\'re around?"\n- "I was checking in on his availability in [month]. I\'m looking to line up 15 clients for them and was wondering if they could handle them. I believe I already talked to someone about this, and weekdays actually work better for me — if you could do [day], that\'d be great."\n\n### Owner\n- "Hey, is this [owner]?"\n- "Great, do you know Charlotte — Charlotte Honeywell by chance?"\n- "She\'s one of your clients and she says great things about your business. She\'s basically your number 1 salesman at this point. I\'ve heard amazing things about you and your business."\n- "I was checking in on your availability in [month]."\n- "I\'m looking to line up 15 clients for you. Would you be able to handle them?"\n- "Well I am going to bring you 15 clients and I am calling to set up a 15-minute Zoom to show you how I am going to do that."\n- "There seems to be a lot of people searching for [niche] in [city] and I see [comp 1] and [comp 2] grabbing all of the attention. I\'d love to steal you for 15 minutes to show you exactly how we take that attention away from them and point it at you, to bring you more clients instead. Does mornings, afternoons, or evenings work better for you?"'

WHERE module_id = 'c48dc95d-60b1-4c33-bb54-f9685192a926'

AND chapter_number = 2;